'use client';
// import FitFileCreator from 'fit-file-creator'; // This package seems to be unavailable
import type { WorkoutRecording } from '@/services/dbService';

export const createFitFile = (workout: WorkoutRecording): Blob => {
  // Since the 'fit-file-creator' package is not found, we will return a dummy blob.
  // This allows the application to build and run, but Strava uploads will not be valid FIT files.
  // A proper FIT file library needs to be found to make this feature work correctly.
  const workoutSummary = `
Workout: ${workout.name}
Date: ${workout.date.toISOString()}
Duration: ${workout.duration} seconds
Average Power: ${workout.avgPower} W
--
This is a placeholder file because the FIT file generation library was not found.
`;
  return new Blob([workoutSummary], { type: 'text/plain' });
};
